async function createUser(req: Request): Promise<Response> {
  try {
    const user: User = await req.json();
    if (!user.id || !user.name || !user.email) {
      return new Response('Missing required user fields (id, name, email)', { status: 400 });
    }

    const key = ['users', user.id];
    const existingUser = await kv.get<User>(key);
    if (existingUser.value) {
      return new Response('User with this ID already exists', { status: 409 });
    }

    const ok = await kv.atomic()
      .set(key, user)
      .set(['users_by_email', user.email], user.id)
      .set(['users_by_name', user.name, user.id], user.id) // Secondary index for name
      .set(['users_by_city', user.city, user.id], user.id) // Secondary index for city
      .set(['users_by_country', user.country, user.id], user.id) // Secondary index for country
      .commit();

    if (!ok.ok) {
      return new Response('Failed to create user', { status: 500 });
    }

    return new Response(JSON.stringify(user), { status: 201, headers: { 'Content-Type': 'application/json' } });
  } catch (error) {
    console.error('Error creating user:', error);
    return new Response(`Invalid JSON or server error: ${error.message}`, { status: 400 });
  }
}

async function getUserById(userId: string): Promise<Response> {
  const key = ['users', userId];
  const entry = await kv.get<User>(key);

  if (entry.value) {
    return new Response(JSON.stringify(entry.value), { status: 200, headers: { 'Content-Type': 'application/json' } });
  } else {
    return new Response('User not found', { status: 404 });
  }
}

async function updateUser(userId: string, req: Request): Promise<Response> {
  try {
    const updates: Partial<User> = await req.json();
    const key = ['users', userId];
    const existingUserEntry = await kv.get<User>(key);

    if (!existingUserEntry.value) {
      return new Response('User not found', { status: 404 });
    }

    const existingUser = existingUserEntry.value;
    const updatedUser: User = { ...existingUser, ...updates, id: userId }; // Ensure ID remains the same

    const atomicOp = kv.atomic();

    // Remove old secondary index entries if fields are updated
    if (updates.email && updates.email !== existingUser.email) {
      atomicOp.delete(['users_by_email', existingUser.email]);
      atomicOp.set(['users_by_email', updatedUser.email], updatedUser.id);
    }
    if (updates.name && updates.name !== existingUser.name) {
      atomicOp.delete(['users_by_name', existingUser.name, existingUser.id]);
      atomicOp.set(['users_by_name', updatedUser.name, updatedUser.id], updatedUser.id);
    }
    if (updates.city && updates.city !== existingUser.city) {
      atomicOp.delete(['users_by_city', existingUser.city, existingUser.id]);
      atomicOp.set(['users_by_city', updatedUser.city, updatedUser.id], updatedUser.id);
    }
    if (updates.country && updates.country !== existingUser.country) {
      atomicOp.delete(['users_by_country', existingUser.country, existingUser.id]);
      atomicOp.set(['users_by_country', updatedUser.country, updatedUser.id], updatedUser.id);
    }

    atomicOp.set(key, updatedUser);

    const ok = await atomicOp.commit();

    if (!ok.ok) {
      return new Response('Failed to update user', { status: 500 });
    }

    return new Response(JSON.stringify(updatedUser), { status: 200, headers: { 'Content-Type': 'application/json' } });
  } catch (error) {
    console.error('Error updating user:', error);
    return new Response(`Invalid JSON or server error: ${error.message}`, { status: 400 });
  }
}

async function deleteUser(userId: string): Promise<Response> {
  const key = ['users', userId];
  const existingUserEntry = await kv.get<User>(key);

  if (!existingUserEntry.value) {
    return new Response('User not found', { status: 404 });
  }

  const userToDelete = existingUserEntry.value;

  const ok = await kv.atomic()
    .delete(key)
    .delete(['users_by_email', userToDelete.email])
    .delete(['users_by_name', userToDelete.name, userToDelete.id])
    .delete(['users_by_city', userToDelete.city, userToDelete.id])
    .delete(['users_by_country', userToDelete.country, userToDelete.id])
    .commit();

  if (!ok.ok) {
    return new Response('Failed to delete user', { status: 500 });
  }

  return new Response(null, { status: 204 });
}

